    [self addChildViewControllerWithController:[[MyViewController alloc] init] andNavigationBarTitle:@"我的" andTabBarTitle:@"我的" andTabBarImageName:@"A_My"];
}

- (void)addChildViewControllerWithController:(UIViewController *)vc
                       andNavigationBarTitle:(NSString *)navTitle
                              andTabBarTitle:(NSString *)tabTitle
                          andTabBarImageName:(NSString *)imageName {

    // 设置标题 - 由内至外设置的
    vc.title = navTitle;
    vc.navigationItem.title = navTitle;
    vc.tabBarItem.title = tabTitle;

    // 设置图像
    vc.tabBarItem.image = [[UIImage imageNamed:imageName] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
    vc.tabBarItem.selectedImage = [[UIImage imageNamed:[imageName stringByAppendingString:@"-Selected"]] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
    // 设置背景
    vc.view.backgroundColor = BACKGROUND_COLOR;

    // 标签栏控制器：标签栏控制器通常与视图控制器一对多绑定
    // 导航控制器：导航栏控制器通常与视图控制器一对一绑定，
    UINavigationController *navVc = [[UINavigationController alloc] initWithRootViewController:vc];

    [self addChildViewController:navVc];
}

#pragma mark 导航样式
- (void)setUpTabBar {
    // 设置tabBar的样式
    UITabBar *tabBar = [UITabBar appearance];
    tabBar.translucent = YES;
    tabBar.tintColor = TAB_COLOR; // 1.item选中时的渲染颜色
    tabBar.unselectedItemTintColor = GREY_COLOR; // 2.item未选中时的渲染颜色

    // 在tabBar上方插入一个视图来模仿悬浮按钮
    UIView *floatingView = [[UIView alloc] init];
    floatingView.backgroundColor = WHITE_COLOR; 
    floatingView.translatesAutoresizingMaskIntoConstraints = NO; // 使用自动布局
    [self.tabBar addSubview:floatingView];
    [NSLayoutConstraint activateConstraints:@[
    [floatingView.topAnchor constraintEqualToAnchor:self.tabBar.topAnchor],
    [floatingView.leadingAnchor constraintEqualToAnchor:self.tabBar.leadingAnchor],
    [floatingView.trailingAnchor constraintEqualToAnchor:self.tabBar.trailingAnchor],
    [floatingView.bottomAnchor constraintEqualToAnchor:self.tabBar.bottomAnchor]
    ]];

    if (@available(iOS 13.0, *)) {
        UITabBarAppearance *tabBarAppearence = [[UITabBarAppearance alloc] init];
        // 重置背景和阴影为透明
        [tabBarAppearence configureWithTransparentBackground];
        // 3> tabBar的颜色
        tabBarAppearence.backgroundColor = CLEAR_COLOR;
        tabBar.standardAppearance = tabBarAppearence;
        if (@available(iOS 15.0, *)) {
            tabBar.scrollEdgeAppearance = tabBarAppearence;
        }
    } else {
        // 3> tabBar的颜色
        tabBar.barTintColor =CLEAR_COLOR;
        // 4> 去除分割线
        tabBar.shadowImage = [UIImage new];
        //tabBar.backgroundImage = [UIImage new];
    }
}

- (void)setUpNavBar {

    // 统一设置所有navigationBar的样式
    UINavigationBar *navBar = [UINavigationBar appearance];
    navBar.translucent = NO;
    // 1> item的渲染颜色
    navBar.tintColor = BLACK_COLOR;

    if (@available(iOS 13.0, *)) {
        UINavigationBarAppearance *navBarAppearence = [[UINavigationBarAppearance alloc] init];
        // 重置背景和阴影为透明
        [navBarAppearence configureWithTransparentBackground];
        // 2> navigationBar的字体样式
        navBarAppearence.titleTextAttributes = @{
            NSForegroundColorAttributeName : RGB(51, 51, 51),
