#pragma mark - SKProductsRequestDelegate

- (void)productsRequest:(SKProductsRequest *)request didReceiveResponse:(SKProductsResponse *)response {
    NSArray *products = response.products;
    if (products.count == 0) {
        [UIView showHUDWithStatus:@"购买失败" imageName:nil];
        NSLog(@"没有获得到对应的商品");
        return;
    }
    // 给属性赋值，方便购买成功后通过skproduct里的period属性得知用户购买的商品是那种vip时长的
    _product = products.firstObject;
    SKPayment *payment = [SKPayment paymentWithProduct:_product];
    [[SKPaymentQueue defaultQueue] addTransactionObserver:self];
    [[SKPaymentQueue defaultQueue] addPayment:payment];
}

#pragma mark - SKPaymentTransactionObserver

- (void)paymentQueue:(SKPaymentQueue *)queue updatedTransactions:(NSArray<SKPaymentTransaction *> *)transactions {
    // 获取商品的时长类型
    SKProductSubscriptionPeriod *period = _product.subscriptionPeriod;
    SKProductPeriodUnit unit = period.unit;
    NSDate *currentDate = [NSDate date];
    NSDate *expireDate = nil;

    SKPaymentTransaction *transaction = transactions.lastObject;
    switch (transaction.transactionState) {
        case SKPaymentTransactionStatePurchased:
            // 计算vip过期日期，保存入userdefault
            switch (unit) {
                case SKProductPeriodUnitDay:
                    expireDate = [currentDate dateByAddingDays:period.numberOfUnits];
                    break;
                case SKProductPeriodUnitWeek:
                    expireDate = [currentDate dateByAddingWeeks:period.numberOfUnits];
                    break;
                case SKProductPeriodUnitMonth:
                    expireDate = [currentDate dateByAddingMonths:period.numberOfUnits];
                    break;
                case SKProductPeriodUnitYear:
                    expireDate = [currentDate dateByAddingYears:period.numberOfUnits];
                    break;
                default:
                    break;
            }
            NSLog(@"%@", [transaction.transactionReceipt base64EncodedStringWithOptions:0]);

            if (_product != nil) {
                [[NSUserDefaults standardUserDefaults] setObject:expireDate forKey:@"vipExpire"];
                [UIView showHUDWithStatus:@"购买成功" imageName:@"Success"];
                NSLog(@"交易完成");
            }
            break;
        case SKPaymentTransactionStateFailed:
            [UIView showHUDWithStatus:@"购买失败" imageName:nil];
            NSLog(@"交易失败，可能是网不好，%@", transaction.error);
            break;
        case SKPaymentTransactionStateRestored:
