    // 用来获得所有cell的btn的开关情况
    NSArray *cells = _collectionView.visibleCells;
    ScrollCollectionCell *cell_0 = cells[0];
    ScrollCollectionCell *cell_1 = cells[1];
    ScrollCollectionCell *cell_2 = cells[2];
    ScrollCollectionCell *cell_3 = cells[3];

    // 如果是下面四个button发来的消息，改变他们的选中状态
    if ([sender isKindOfClass:[UISwitch class]]) {
        UISwitch *clickedSwitch = sender;

        // 根据点击的 UISwitch 来调整其他 UISwitch 的状态
        if (clickedSwitch.tag == 0) {
            cell_1.btn.on = !clickedSwitch.on;
            self.isLandscapeEnabled = clickedSwitch.on;     // 启用横屏模式
        } else if (clickedSwitch.tag == 1) {
            cell_0.btn.on = !clickedSwitch.on;
            self.isLandscapeEnabled = !clickedSwitch.on;    // 启用竖屏模式
        } else if (clickedSwitch.tag == 2) {
            cell_3.btn.on = !clickedSwitch.on;
            self.isScrollingEnabled = !clickedSwitch.on;    // 静态弹幕
        } else if (clickedSwitch.tag == 3) {
            cell_2.btn.on = !clickedSwitch.on;
            self.isScrollingEnabled = clickedSwitch.on;     // 滚动弹幕
        }

        // 检查 0 号和 1 号 UISwitch 是否都未被选中
        if (!cell_0.btn.on && !cell_1.btn.on) {
            clickedSwitch.on = !clickedSwitch.on;
            return;
        }

        // 检查 2 号和 3 号 UISwitch 是否都未被选中
        if (!cell_2.btn.on && !cell_3.btn.on) {
            clickedSwitch.on = !clickedSwitch.on;
            return;
        }
    }
}


