- (void)GET:(NSString *)path params:(NSDictionary *)params callback:(WBNetworkBaseCallback)callback {
    [self requestWithMethod:@"GET" path:path params:params callback:callback];
}

// 辅助方法：构建带有查询参数的 URL
- (NSURL *)buildURLWithPath:(NSString *)path params:(NSDictionary *)params {
    // 构建基础 URL
    NSString *baseUrlString = [self.baseURL stringByAppendingString:path];
    NSURL *baseURL = [NSURL URLWithString:baseUrlString];

    // 如果没有参数，直接返回基础 URL
    if (!params || params.count == 0) {
        return baseURL;
    }

    // 将参数转换为查询字符串
    NSMutableArray *queryItems = [NSMutableArray array];
    for (NSString *key in params.allKeys) {
        id rawValue = params[key];
        NSString *valueString = [self stringFromParamValue:rawValue];
        NSString *encodedKey = [key stringByAddingPercentEncodingWithAllowedCharacters:[NSCharacterSet URLQueryAllowedCharacterSet]];
        NSString *encodedValue = [valueString stringByAddingPercentEncodingWithAllowedCharacters:[NSCharacterSet URLQueryAllowedCharacterSet]];
        if (encodedKey && encodedValue) {
            [queryItems addObject:[NSString stringWithFormat:@"%@=%@", encodedKey, encodedValue]];
        }
    }

    // 将查询字符串附加到 URL
    NSString *queryString = [queryItems componentsJoinedByString:@"&"];
    NSString *finalURLString = [NSString stringWithFormat:@"%@?%@", baseUrlString, queryString];

    return [NSURL URLWithString:finalURLString];
}

- (NSString *)encodedQueryStringFromParams:(NSDictionary *)params {
    NSMutableArray *queryItems = [NSMutableArray array];
    for (NSString *key in params.allKeys) {
        id rawValue = params[key];
        NSString *valueString = [self stringFromParamValue:rawValue];
        NSString *encodedKey = [key stringByAddingPercentEncodingWithAllowedCharacters:[NSCharacterSet URLQueryAllowedCharacterSet]];
        NSString *encodedValue = [valueString stringByAddingPercentEncodingWithAllowedCharacters:[NSCharacterSet URLQueryAllowedCharacterSet]];
        if (encodedKey && encodedValue) {
            [queryItems addObject:[NSString stringWithFormat:@"%@=%@", encodedKey, encodedValue]];
        }
    }
    return [queryItems componentsJoinedByString:@"&"];
}

- (NSString *)stringFromParamValue:(id)value {
    if (!value || value == [NSNull null]) {
        return @"";
    }
    if ([value isKindOfClass:NSString.class]) {
        return (NSString *)value;
    }
    if ([value isKindOfClass:NSNumber.class]) {
        return [(NSNumber *)value stringValue];
    }
    if ([value isKindOfClass:NSArray.class] || [value isKindOfClass:NSDictionary.class]) {
        NSError *error = nil;
        NSData *data = [NSJSONSerialization dataWithJSONObject:value options:0 error:&error];
        if (data && !error) {
            return [[NSString alloc] initWithData:data encoding:NSUTF8StringEncoding];
        }
    }
    return [value description];
}

- (void)requestWithMethod:(NSString *)method path:(NSString *)path params:(NSDictionary *)params callback:(WBNetworkBaseCallback)callback {
    NSURL *url;
    if ([method isEqualToString:@"GET"]) {
        url = [self buildURLWithPath:path params:params];
    } else {
        url = [NSURL URLWithString:[self.baseURL stringByAppendingString:path]];
    }
    NSMutableURLRequest *request = [NSMutableURLRequest requestWithURL:url];
    [request setHTTPMethod:method];
    if (![method isEqualToString:@"GET"] && params && params.count > 0) {
        NSString *postString = [self encodedQueryStringFromParams:params];
        [request setValue:@"application/x-www-form-urlencoded" forHTTPHeaderField:@"Content-Type"];
        [request setHTTPBody:[postString dataUsingEncoding:NSUTF8StringEncoding]];
    }
    [self performRequest:request callback:callback];
}

- (void)performRequest:(NSMutableURLRequest *)request callback:(WBNetworkBaseCallback)callback {
    NSURLSessionDataTask *dataTask = [[NSURLSession sharedSession] dataTaskWithRequest:request completionHandler:^(NSData * _Nullable data, NSURLResponse * _Nullable response, NSError * _Nullable error) {
        if (error) {
            NSLog(@"Error fetching data: %@", error.localizedDescription);
            if (callback) {
                callback(nil, error);
            }
            return;
        }
        NSError *jsonError;
        id jsonResponse = data ? [NSJSONSerialization JSONObjectWithData:data options:0 error:&jsonError] : nil;
        if (jsonError) {
            NSLog(@"Error parsing JSON: %@", jsonError.localizedDescription);
            if (callback) {
                callback(nil, jsonError);
            }
            return;
        }
        dispatch_async(dispatch_get_main_queue(), ^{
            if (callback) {
                if (jsonResponse == [NSNull null]) {
                    callback(nil, nil);
                } else {
                    callback(jsonResponse, nil);
                }
            }
        });
    }];
    [dataTask resume];
}

- (void)uploadFeedbackWithParams:(NSDictionary *)params imageURL:(NSURL *)imageURL callback:(WBNetworkBaseCallback)callback {
    NSData *imageData = nil;
    NSString *fileName = @"upload.jpg";
    NSString *mimeType = @"image/jpeg";

    if (imageURL.isFileURL) {
        imageData = [NSData dataWithContentsOfURL:imageURL];
        if (imageURL.lastPathComponent.length > 0) {
            fileName = imageURL.lastPathComponent;
        }
        NSString *ext = imageURL.pathExtension.lowercaseString;
        if ([ext isEqualToString:@"png"]) {
            mimeType = @"image/png";
        } else if ([ext isEqualToString:@"heic"] || [ext isEqualToString:@"heif"]) {
            mimeType = @"image/heic";
        }
    }

    if (!imageData || imageData.length == 0) {
        NSError *error = [NSError errorWithDomain:@"NetworkManager" code:-3 userInfo:@{NSLocalizedDescriptionKey: @"图片文件读取失败"}];
        if (callback) { callback(nil, error); }
        return;
    }

    NSString *boundary = [NSString stringWithFormat:@"Boundary-%@", NSUUID.UUID.UUIDString];
    NSMutableData *body = [NSMutableData data];
    [params enumerateKeysAndObjectsUsingBlock:^(id key, id obj, BOOL *stop) {
        NSString *value = [self stringFromParamValue:obj];
        [body appendData:[[NSString stringWithFormat:@"--%@\r\n", boundary] dataUsingEncoding:NSUTF8StringEncoding]];
        [body appendData:[[NSString stringWithFormat:@"Content-Disposition: form-data; name=\"%@\"\r\n\r\n", key] dataUsingEncoding:NSUTF8StringEncoding]];
        [body appendData:[[NSString stringWithFormat:@"%@\r\n", value] dataUsingEncoding:NSUTF8StringEncoding]];
    }];

    [body appendData:[[NSString stringWithFormat:@"--%@\r\n", boundary] dataUsingEncoding:NSUTF8StringEncoding]];
    [body appendData:[[NSString stringWithFormat:@"Content-Disposition: form-data; name=\"image\"; filename=\"%@\"\r\n", fileName] dataUsingEncoding:NSUTF8StringEncoding]];
    [body appendData:[[NSString stringWithFormat:@"Content-Type: %@\r\n\r\n", mimeType] dataUsingEncoding:NSUTF8StringEncoding]];
    [body appendData:imageData];
    [body appendData:[@"\r\n" dataUsingEncoding:NSUTF8StringEncoding]];
    [body appendData:[[NSString stringWithFormat:@"--%@--\r\n", boundary] dataUsingEncoding:NSUTF8StringEncoding]];

    NSURL *url = [NSURL URLWithString:[self.baseURL stringByAppendingString:@"aface/send"]];
    NSMutableURLRequest *request = [NSMutableURLRequest requestWithURL:url];
    request.HTTPMethod = @"POST";
    [request setValue:[NSString stringWithFormat:@"multipart/form-data; boundary=%@", boundary] forHTTPHeaderField:@"Content-Type"];
    request.HTTPBody = body;
    [self performRequest:request callback:callback];
}

