@interface TopicTalkViewController () <UITableViewDelegate, UITableViewDataSource, UITextFieldDelegate, NSURLSessionDataDelegate>

@property(strong, nonatomic) MessageSendView *messageView;
@property(strong, nonatomic) UITableView *chatTableView;
@property(strong, nonatomic) NSMutableArray<MessageModel *> *messages;
@property (nonatomic, assign) BOOL isDeleting;
// 以下属性用于消息拼接实现流式显示效果
@property(strong, nonatomic) NSMutableString *accumulatedResponse;
@property(strong, nonatomic) NSMutableString *buffer;
@property(strong, nonatomic) NSString *nowString;
@property(strong, nonatomic) NSString *preString;
@property (nonatomic, strong) NSURLSessionDataTask *dataTask;
@property (nonatomic, strong) NSArray *context;

@end

@implementation TopicTalkViewController
#pragma mark - Initialization


- (instancetype)init {
    self = [super init];
    if (self) {
        self.view.backgroundColor = BACKGROUND_COLOR;
        // 设置modal出来的模式是占满全屏幕
        self.modalPresentationStyle = UIModalPresentationFullScreen;
        // 添加通知观察者
        [self addObservers];

    }
    return self;
}

- (instancetype)initWithAccount:(AccountModel *)account Data:(NSString *)options{
    self = [super init];
    if (self) {
        // 在初始化时进行赋值
        self.name = account.aiName;
        self.aiID = account.ID;
        self.headerView.titleLabel.text = account.aiName;
        self.headerView.editButton.hidden = YES;
        self.iconimage = [UIImage imageNamed:@"My_image"];
        self.options = options;
        self.view.backgroundColor = BACKGROUND_COLOR;
        // 设置modal出来的模式是占满全屏幕
        self.modalPresentationStyle = UIModalPresentationFullScreen;
        // 添加通知观察者
        [self addObservers];
    }
    return self;
}

- (void)addObservers {

    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(keyboardWillShow:) name:UIKeyboardWillShowNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(keyboardWillHide:) name:UIKeyboardWillHideNotification object:nil];
    // 添加通知观察者
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(onSendMessageButtonTapped:) name:@"发送了一条消息" object:nil];
}

#pragma mark - loadView & viewDidLoad & viewDidAppear & dealloc

- (void)loadView { // 创建并设置视图控制器的 view 属性
    [super loadView];
    [self setUpUI];
}

- (void)viewDidLoad { // 在视图控制器的 view 属性已经被加载到内存后调用。此时视图层次结构已经创建完成，通常用于视图的额外配置和初始化。
    [super viewDidLoad];
    self.accumulatedResponse = [[NSMutableString alloc] init];
    self.buffer = [[NSMutableString alloc] init];
    self.isDeleting=NO;
    [self setupMessages]; // 初始化消息数组
    [self setupDelegates]; // 设置代理
    [self scrollToBottom]; // 滚动到最下方最新消息
}

- (void)viewDidAppear:(BOOL)animated { //会在视图控制器的视图已经完全显示并且用户可以看到时被调用
    [super viewDidAppear:animated];
    [_headerView showAppearAnimation];
    [self.chatTableView reloadData]; // 刷新表格视图以显示消息
}

- (void)viewDidDisappear:(BOOL)animated {
    [super viewDidDisappear:animated];
    // 删除操作时出现一些bug，目前只能通过这种方法修改
    // 检测最后一条消息是否已经显示出来了，如果已经显示出来了就保留，如果还是"思考中"则删除最后一条消息
    if((![self.messages.lastObject.text isEqual:@"思考中..."])&&self.messages.count>1&&(!self.messages.lastObject.done)&&(!self.isDeleting)){
        self.messages.lastObject.context = self.messages[self.messages.count-3].context;
        self.messages.lastObject.done = YES;
        self.messages[self.messages.count-2].done=YES;
        self.messages[self.messages.count-3].context=@"";
        [MessageModel saveMessagesForAccount:self.aiID]; // 保存消息
        self.messageView.inputMessageField.enabled = YES;
        self.messageView.sendButton.enabled = YES; // 按钮恢复可点击
        self.messageView.sendButton.alpha = 1.0; // 恢复透明度
    }
    // 删除时也需要检测是否有任务存在且未完成，有则取消任务
    if (self.dataTask) {
        [self.dataTask cancel];
        self.dataTask = nil;  // 释放任务
    }
}

- (void)dealloc { //当一个视图控制器的生命周期结束且没有其他地方再引用它时，dealloc 会被调用。
    // 移除观察者
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

#pragma mark - UI Setup

- (void)setUpUI {
    [self.view addSubview:self.headerView];
    [self.view addSubview:self.chatTableView];
    [self.view addSubview:self.messageView];

    // 设置headerView约束
    [_headerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view);
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.height.mas_equalTo(ZOOM(86));
    }];

    // 设置chatTableView约束
    [_chatTableView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.headerView.mas_bottom);
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.bottom.equalTo(self.messageView.mas_top);
    }];

    // 设置messageView约束
    [_messageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.bottom.equalTo(self.view);
        make.height.mas_equalTo(ZOOM(88));
        make.width.mas_equalTo(self.view.width);
    }];

}

//Message初始化
- (void)setupMessages {
    [self.chatTableView registerClass:[ChatMessageCell class] forCellReuseIdentifier:@"ChatMessageCell"]; // 注册消息单元格类
    self.messages = [MessageModel messagesForAccount:self.aiID];
    if (self.messages.count == 0) {
        [self.messages addObject:[[MessageModel alloc] initWithText:self.options time:[NSDate date] type:MessageTypeReceived accountId:self.aiID cellHeight:[self getStringWidthToCellHeight:self.options] context:@"[]" Done:YES]];
    }
    // 获取最后一个消息，判断接收ai消息时是否被中断，最后一次对话无法完成，所以在这里删除
    MessageModel *lastMessage = [self.messages lastObject];
    if (!lastMessage.done) {
        // 删除最后两个元素
        [self.messages removeLastObject];
        [self.messages removeLastObject];
    }
}

- (void)setupDelegates {
    self.chatTableView.delegate = self;
    self.chatTableView.dataSource = self; // 添加数据源
    self.messageView.inputMessageField.delegate = self;
}

#pragma mark - UITableViewDataSource

- (NSInteger)tableView:(UITableView *)tableView numberOfRowsInSection:(NSInteger)section {
    // 返回消息的数量
    return self.messages ? [self.messages count] : 0;
}

- (UITableViewCell *)tableView:(UITableView *)tableView cellForRowAtIndexPath:(NSIndexPath *)indexPath {
    ChatMessageCell *cell = [tableView dequeueReusableCellWithIdentifier:@"ChatMessageCell" forIndexPath:indexPath];
    // 根据索引路径配置单元格
    MessageModel *message = self.messages[indexPath.row];
    UIImage* sicon = [UIImage imageNamed:@"DeUseravatar"];

    [cell configureWithMessage:message iconSendImage:sicon iconReceiveImage:self.iconimage topicName:self.name options:self.options];

    //[cell layoutIfNeeded];
    return cell;
}

#pragma mark - UITableViewDelegate

- (CGFloat)tableView:(UITableView *)tableView heightForRowAtIndexPath:(NSIndexPath *)indexPath {
    MessageModel *message = self.messages[indexPath.row];
    return message.cellHeight > 0 ? message.cellHeight : 60.0;
}

- (void)tableView:(UITableView *)tableView didSelectRowAtIndexPath:(NSIndexPath *)indexPath {
    // 关闭键盘
    [self.messageView.inputMessageField resignFirstResponder];
}

#pragma mark - 编辑对话信息

- (void)updateDialogTitle:(NSString *)newTitle {
    _headerView.titleLabel.text = newTitle;
}
- (void)handleDeleteNotification:(NSNotification *)notification {
    BOOL isDeleting = [notification.userInfo[@"isDeleting"] boolValue];
    self.isDeleting = isDeleting;
}
+ (void)deleteTalkNotification {
    [[NSNotificationCenter defaultCenter] postNotificationName:@"删除对话" object:nil];
}
#pragma mark - 键盘事件处理
- (BOOL)textFieldShouldReturn:(UITextField *)textField {
    if (textField == self.messageView.inputMessageField) {
        [textField resignFirstResponder];
    }
    return YES;
}
- (void)keyboardWillShow:(NSNotification *)notification {
    // 获取键盘的高度
    CGSize keyboardSize = [[[notification userInfo] objectForKey:UIKeyboardFrameEndUserInfoKey] CGRectValue].size;
    // 调整消息输入框的位置
    [_messageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.bottom.equalTo(self.view).offset(-keyboardSize.height + 33);
    }];
}
- (void)keyboardWillHide:(NSNotification *)notification {
    [_messageView mas_updateConstraints:^(MASConstraintMaker *make) {
        make.bottom.equalTo(self.view);
    }];
}
#pragma mark - 计算消息文本内容的高度和换行情况

- (NSInteger)getStringWidthToCellHeight:(NSString *)string {
    // 将文本分割为行
    NSArray *lines = [string componentsSeparatedByString:@"\n"];

    // 计算空行数
    NSPredicate *isEmptyLinePredicate = [NSPredicate predicateWithBlock:^BOOL(id _Nullable evaluatedObject, NSDictionary * _Nullable bindings) {
        return ([evaluatedObject isKindOfClass:[NSString class]] && [(NSString *)evaluatedObject length] == 0);
    }];
    NSArray *emptyLines = [lines filteredArrayUsingPredicate:isEmptyLinePredicate];
    NSInteger emptyLineCount = (NSInteger)emptyLines.count;

    // 使用系统字体进行计算
    UIFont *font = [UIFont systemFontOfSize:16.0];

    // 计算实际文本的行数
    CGFloat totalTextHeight = 0.0;
    for (NSString *line in lines) {
        if (![emptyLines containsObject:line]) { // 只处理非空行
            // 使用boundingRect来计算文本占用的实际高度
            CGSize maxSize = CGSizeMake(ZOOMW(260), CGFLOAT_MAX);  // 最大宽度

            CGRect textRect = [line boundingRectWithSize:maxSize
                                                  options:NSStringDrawingUsesLineFragmentOrigin
                                               attributes:@{NSFontAttributeName: font}
                                                  context:nil];
            // 每一行的高度由文本占用的高度决定
            totalTextHeight += textRect.size.height;
        }
    }

    // 计算 cell 的总高度
    CGFloat cellHeight = totalTextHeight              // 计算所有文本行的总高度
                       + emptyLineCount * ZOOM(19)  // 计算空行的高度
                       + ZOOM(40);                  // 添加气泡上下的间距（已涵盖所有间距）
    NSLog(@"cellHeight:%lf",cellHeight-ZOOM(40));
    return cellHeight;
}

#pragma mark - 滚动操作
- (void)scrollToBottom {
    if (self.messages.count > 0) {
        NSIndexPath *indexPath = [NSIndexPath indexPathForRow:self.messages.count - 1 inSection:0];
        dispatch_async(dispatch_get_main_queue(), ^{
            [self.chatTableView scrollToRowAtIndexPath:indexPath atScrollPosition:UITableViewScrollPositionBottom animated:YES];
        });
    }
}
#pragma mark - 消息处理
- (void)onSendMessageButtonTapped:(NSNotification *)notification {
    // 获取输入框中的消息内容
    NSString *messageText ;
    if(notification.object){
        messageText=notification.object;
    }
    else{
        // 获取输入框中的消息内容
        messageText = _messageView.inputMessageField.text;
    }

    // 检测是否为空消息，纯空格或者纯换行符
    NSString *trimmedString = [messageText stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    if ([messageText isEqualToString:@""]||[trimmedString length] == 0) {
        // 如果消息为空，则不处理
        return;
    }
    // 所发消息需要的显示高度
    CGFloat cellHeight = [self getStringWidthToCellHeight:messageText];
    // 创建新的发送消息对象，这里context从上一条MessageTypeReceived属性的MessageModel中或许
    [self.messages addObject:[[MessageModel alloc] initWithText:messageText time:[NSDate date] type:MessageTypeSent accountId:self.aiID cellHeight:cellHeight context:@"" Done:NO]];
    [self.messages addObject:[[MessageModel alloc] initWithText:@"思考中..." time:[NSDate date] type:MessageTypeReceived accountId:self.aiID cellHeight:[self getStringWidthToCellHeight:@"思考中..."] context:self.messages[self.messages.count-2].context Done:NO]];
    // 清空输入框
    _messageView.inputMessageField.text = @"";
    [self.chatTableView reloadData];    // 刷新表格视图以显示新的消息
    [self scrollToBottom];  // 滚动到最下方最新消息
    [MessageModel saveMessagesForAccount:self.aiID];    // 保存消息
    self.messageView.inputMessageField.enabled = NO;
    self.messageView.sendButton.enabled = NO;  // 按钮不可点击
    self.messageView.sendButton.alpha = 0.5;  // 透明度也可以稍微降低表示不可点击状态
    [self sendPOSTRequestAndHandleStreamResponse:messageText];  // 发送消息，接收ai应答信息
}
#pragma mark - 网络请求
/*
 使用NSURLSessionDataDelegate和didReceiveData而非completionHandler
 底层差异：
 数据流和缓冲机制的差异：
 NSURLSessionDataDelegate：基于 数据流，数据分批传输到应用层，系统只负责接收，处理逻辑由开发者决定。每个数据块到达时，didReceiveData: 方法被调用，允许你立即处理数据。
 completionHandler：基于 缓冲机制，系统负责将所有数据接收完毕并缓存在本地，只有当全部数据接收完毕后才调用 completionHandler，并将数据一次性提供给应用层。
 触发时机的差异：
 NSURLSessionDataDelegate：代理方法根据网络传输状态多次触发。每当数据从网络到达时，系统会调用代理方法，开发者可以在这些调用中实时处理数据。
 completionHandler：只有在数据完全接收后，才会一次性触发。你无法在数据传输过程中干预或处理部分数据。
 */
// 发送POST请求并处理流响应
- (void)sendPOSTRequestAndHandleStreamResponse:(NSString *)messageText {
    // 配置 URL 和请求
    NSURL *url = [NSURL URLWithString:@"https://xportal.sposervice.com/ai"];
    NSMutableURLRequest *request = [NSMutableURLRequest requestWithURL:url];
    request.HTTPMethod = @"POST";
    [request setValue:@"application/json" forHTTPHeaderField:@"Content-Type"];
    // 每次开始新对话时要初始化如下内容
    _nowString=nil;
    // 注意：这里accumulatedResponse和buffer和是一个可变字符串，不要赋空，而要赋为空串
    [self.buffer setString:@""];
    [self.accumulatedResponse setString:@""];
    NSDictionary *params;
    if(self.messages.lastObject.context==nil){
        self.context=@[];
    }
    else{
        NSData *jsonData = [self.messages.lastObject.context dataUsingEncoding:NSUTF8StringEncoding];
        NSError *error;
        self.context = [NSJSONSerialization JSONObjectWithData:jsonData options:0 error:&error];
        if (error) {
            NSLog(@"Error parsing JSON: %@", error.localizedDescription);
            self.context=@[];
        }
    }
    if(self.Identity == nil){
        params = @{@"model": @"gemma2:2b",
                   @"prompt": messageText,
                   @"context": self.context
        };
    }
    else{
        params = @{@"model": @"gemma2:2b",
                   @"prompt": messageText,
                   @"context": self.context,
                   @"system":self.Identity
        };
    }
    NSData *postData = [NSJSONSerialization dataWithJSONObject:params options:0 error:nil];
    request.HTTPBody = postData;
    // 创建一个会话配置
    NSURLSessionConfiguration *sessionConfig = [NSURLSessionConfiguration defaultSessionConfiguration];
    // 创建 NSURLSession，并设置 delegate 和 delegateQueue
    NSURLSession *session = [NSURLSession sessionWithConfiguration:sessionConfig delegate:self delegateQueue:nil];
    self.dataTask = [session dataTaskWithRequest:request];
    [self.dataTask resume];
}

