- (void)processDoneMessage:(NSDictionary *)Dict{
    dispatch_async(dispatch_get_main_queue(), ^{
        // 提取 context
        NSArray *lastContext = self.context;
        NSArray *ReContext = Dict[@"context"];
        // 确保不超出 bounds
        NSRange range;
        NSArray *contextArray;
        // 确保不超出 bounds
        if (ReContext.count == 1||lastContext.count < ReContext.count) {  //服务器哪里有一个特殊消息，里面的context=[1];
            // 当 ReContext.count 为 1 时，直接将 contextArray 设为 lastContext
            contextArray = lastContext;
        } else {
            range = NSMakeRange(lastContext.count, ReContext.count - lastContext.count);
            contextArray = [ReContext subarrayWithRange:range];
        }
        NSError *error;
        NSData *jsonData = [NSJSONSerialization dataWithJSONObject:contextArray options:0 error:&error];
